using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Ingredients = new() { "Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt" },
            Steps = new() { "Preheat oven to 475°F.", "Roll out dough on a floured surface.", "Spread crushed tomatoes evenly.", "Add torn mozzarella pieces.", "Bake for 10-12 minutes.", "Top with fresh basil and drizzle olive oil." },
            AverageRating = 4.5, RatingCount = 12
        },
        new Recipe
        {
            Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
            Ingredients = new() { "Spaghetti", "Guanciale", "Egg yolks", "Pecorino Romano", "Black pepper" },
            Steps = new() { "Cook spaghetti in salted boiling water.", "Crisp guanciale in a pan.", "Whisk egg yolks with grated pecorino.", "Toss hot pasta with guanciale.", "Remove from heat, stir in egg mixture.", "Season with black pepper and serve." },
            AverageRating = 4.8, RatingCount = 20
        },
        new Recipe
        {
            Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
            Ingredients = new() { "Chicken thighs", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Garlic", "Ginger", "Onion" },
            Steps = new() { "Marinate chicken in yogurt and spices for 2 hours.", "Grill or broil chicken until charred.", "Sauté onion, garlic, and ginger.", "Add tomato sauce and simmer.", "Stir in cream and garam masala.", "Add chicken pieces and simmer 10 minutes." },
            AverageRating = 4.6, RatingCount = 15
        },
        new Recipe
        {
            Id = 4, Title = "Vegetable Biryani", Category = "Indian",
            Ingredients = new() { "Basmati rice", "Mixed vegetables", "Onions", "Biryani masala", "Saffron", "Ghee", "Mint leaves", "Yogurt" },
            Steps = new() { "Soak rice for 30 minutes.", "Fry onions until golden.", "Cook vegetables with spices.", "Layer rice and vegetables in a pot.", "Add saffron milk and ghee.", "Seal and cook on low heat for 25 minutes." },
            AverageRating = 4.3, RatingCount = 8
        },
        new Recipe
        {
            Id = 5, Title = "Beef Tacos", Category = "Mexican",
            Ingredients = new() { "Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheese", "Sour cream", "Salsa" },
            Steps = new() { "Brown ground beef in a skillet.", "Add taco seasoning and water.", "Simmer until thickened.", "Warm tortillas.", "Assemble tacos with toppings.", "Serve with salsa and sour cream." },
            AverageRating = 4.2, RatingCount = 18
        },
        new Recipe
        {
            Id = 6, Title = "Guacamole", Category = "Mexican",
            Ingredients = new() { "Avocados", "Lime juice", "Red onion", "Cilantro", "Jalapeño", "Salt", "Tomato" },
            Steps = new() { "Halve and pit avocados.", "Mash avocado flesh in a bowl.", "Add diced onion, tomato, and jalapeño.", "Stir in cilantro and lime juice.", "Season with salt to taste.", "Serve immediately with chips." },
            AverageRating = 4.7, RatingCount = 25
        },
        new Recipe
        {
            Id = 7, Title = "Chocolate Lava Cake", Category = "Desserts",
            Ingredients = new() { "Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract" },
            Steps = new() { "Preheat oven to 425°F.", "Melt chocolate and butter together.", "Whisk eggs and sugar until thick.", "Fold in chocolate mixture.", "Add flour and vanilla.", "Bake in greased ramekins for 12 minutes." },
            AverageRating = 4.9, RatingCount = 30
        },
        new Recipe
        {
            Id = 8, Title = "Miso Soup", Category = "Japanese",
            Ingredients = new() { "Dashi stock", "White miso paste", "Tofu", "Wakame seaweed", "Green onions" },
            Steps = new() { "Heat dashi stock in a pot.", "Add cubed tofu and wakame.", "Simmer for 2 minutes.", "Remove from heat.", "Dissolve miso paste into the broth.", "Garnish with sliced green onions." },
            AverageRating = 4.1, RatingCount = 10
        }
    };

    private readonly List<(int RecipeId, int Rating)> _ratings = new();

    public List<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int rating)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is null || rating < 1 || rating > 5) return;

        _ratings.Add((recipeId, rating));
        var recipeRatings = _ratings.Where(r => r.RecipeId == recipeId).ToList();
        recipe.RatingCount = recipeRatings.Count;
        recipe.AverageRating = Math.Round(recipeRatings.Average(r => r.Rating), 1);
    }

    public void SubmitRecipe(RecipeSubmission submission)
    {
        var newId = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(new Recipe
        {
            Id = newId,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries).ToList(),
            Steps = submission.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries).ToList(),
            AverageRating = 0,
            RatingCount = 0
        });
    }
}

