@using RecipeCommunity.Services
@using RecipeCommunity.Models
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - Recipe Community</PageTitle>

<div class="container">
    <h1>📝 Submit a Recipe</h1>
    <p class="text-muted">Share your favorite recipe with the community!</p>

    @if (Submitted)
    {
        <div class="alert alert-success">
            <h4>🎉 Recipe submitted successfully!</h4>
            <p>Your recipe "<strong>@Submission.Title</strong>" has been added to the community.</p>
            <a href="/" class="btn btn-primary">Back to Home</a>
        </div>
    }
    else
    {
        <EditForm Model="@Submission" OnValidSubmit="HandleSubmit" FormName="recipeForm">
            <div class="row">
                <div class="col-md-8">
                    <div class="mb-3">
                        <label for="title" class="form-label">Recipe Title</label>
                        <InputText id="title" @bind-Value="Submission.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
                    </div>

                    <div class="mb-3">
                        <label for="category" class="form-label">Category</label>
                        <InputSelect id="category" @bind-Value="Submission.Category" class="form-select">
                            <option value="">Select a category...</option>
                            <option value="Italian">Italian</option>
                            <option value="Indian">Indian</option>
                            <option value="Mexican">Mexican</option>
                            <option value="Japanese">Japanese</option>
                            <option value="Desserts">Desserts</option>
                            <option value="Other">Other</option>
                        </InputSelect>
                    </div>

                    <div class="mb-3">
                        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
                        <InputTextArea id="ingredients" @bind-Value="Submission.Ingredients" class="form-control" rows="6" placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
                    </div>

                    <div class="mb-3">
                        <label for="steps" class="form-label">Steps (one per line)</label>
                        <InputTextArea id="steps" @bind-Value="Submission.Steps" class="form-control" rows="6" placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients" />
                    </div>

                    <button type="submit" class="btn btn-primary btn-lg"
                            disabled="@(!IsValid)">
                        Submit Recipe
                    </button>
                </div>
            </div>
        </EditForm>
    }
</div>

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private RecipeSubmission Submission { get; set; } = new();
    private bool Submitted { get; set; }

    private bool IsValid =>
        !string.IsNullOrWhiteSpace(Submission.Title) &&
        !string.IsNullOrWhiteSpace(Submission.Category) &&
        !string.IsNullOrWhiteSpace(Submission.Ingredients) &&
        !string.IsNullOrWhiteSpace(Submission.Steps);

    private void HandleSubmit()
    {
        if (!IsValid) return;
        RecipeService.SubmitRecipe(Submission);
        Submitted = true;
    }
}

