{"file_text": "@page "/recipes/{Category}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models

<PageTitle>@Category Recipes - Recipe Community</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">@Category</li>
        </ol>
    </nav>

    <h1>@Category Recipes</h1>

    @if (Recipes.Any())
    {
        <div class="row g-3">
            @foreach (var recipe in Recipes)
            {
                <div class="col-md-6">
                    <div class="card h-100 shadow-sm">
                        <div class="card-body">
                            <h5 class="card-title">
                                <a href="/recipe/@recipe.Id">@recipe.Title</a>
                            </h5>
                            <p class="card-text text-muted">
                                @if (recipe.RatingCount > 0)
                                {
                                    <span>⭐ @recipe.AverageRating (@recipe.RatingCount ratings)</span>
                                }
                                else
                                {
                                    <span>No ratings yet</span>
                                }
                            </p>
                            <p class="card-text">
                                <small>@recipe.Ingredients.Count ingredients · @recipe.Steps.Count steps</small>
                            </p>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
    else
    {
        <div class="alert alert-info">No recipes found in this category.</div>
    }
</div>

@code {
    [Parameter] public string Category { get; set; } = string.Empty;
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private List<Recipe> Recipes { get; set; } = new();

    protected override void OnParametersSet()
    {
        var formatted = System.Globalization.CultureInfo.CurrentCulture.TextInfo.ToTitleCase(Category);
        Recipes = RecipeService.GetRecipesByCategory(formatted);
        Category = formatted;
    }
}
