{"file_text": "@using RecipeCommunity.Services
@rendermode InteractiveServer

<div class="d-inline-flex align-items-center gap-2">
    <span class="fw-bold">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="btn btn-link p-0 fs-4 text-decoration-none"
                @onclick="() => Rate(star)"
                title="Rate @star stars">
            @(star <= SelectedRating ? "★" : "☆")
        </button>
    }
    @if (SelectedRating > 0)
    {
        <span class="text-success ms-2">You rated @SelectedRating/5</span>
    }
    @if (AverageRating > 0)
    {
        <span class="text-muted ms-2">Average: @AverageRating ⭐ (@RatingCount ratings)</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private int SelectedRating { get; set; }
    private double AverageRating { get; set; }
    private int RatingCount { get; set; }

    protected override void OnInitialized()
    {
        LoadRating();
    }

    private void Rate(int rating)
    {
        SelectedRating = rating;
        RecipeService.AddRating(RecipeId, rating);
        LoadRating();
    }

    private void LoadRating()
    {
        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            AverageRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
    }
}
