@page "/"
@using RecipeCommunity.Services

<PageTitle>Recipe Community</PageTitle>

<div class="container">
    <div class="text-center my-4">
        <h1>🍳 Recipe Community</h1>
        <p class="lead">Discover and share delicious recipes from around the world</p>
    </div>

    <h2>Browse by Category</h2>
    <div class="row g-3">
        @foreach (var category in Categories)
        {
            <div class="col-md-4 col-sm-6">
                <a href="/recipes/@category.ToLower()" class="text-decoration-none">
                    <div class="card h-100 shadow-sm">
                        <div class="card-body text-center">
                            <h4 class="card-title">@GetCategoryEmoji(category) @category</h4>
                            <p class="card-text text-muted">Explore @category recipes</p>
                        </div>
                    </div>
                </a>
            </div>
        }
    </div>
</div>

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private List<string> Categories { get; set; } = new();

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }

    private string GetCategoryEmoji(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Mexican" => "🌮",
        "Desserts" => "🍰",
        "Japanese" => "🍣",
        _ => "🍽️"
    };
}

